const express = require('express');
const { execFile } = require('child_process');
const app = express();
app.use(express.json());

app.post('/run', (req, res) => {
  // Fixed: argv array, no shell.
  const target = String(req.body.target || '');
  if (!/^[a-zA-Z0-9.-]{1,253}$/.test(target)) return res.status(400).end();
  execFile('nslookup', [target], (err, stdout) => {
    if (err) return res.status(500).end();
    res.type('text/plain').end(stdout);
  });
});

app.listen(3000);
